window.SOTA_MAINTENANCE_RECIPES = [{"id":"bbq-season-rub","title":"BBQ Season Rub","category":"sauces","tags":["spicy"],"servings":"Serves 2","ingredients":["1/4 cup paprika","2 tbsp kosher salt","1 tbsp mustard powder","2 tbsp chili powder","2 tbsp ground cumin","1 tbsp black pepper","2 tbsp garlic powder","1 tbsp cayenne","1 tbsp onion powder"],"instructions":["Mix all spices together.","Store in a pint-sized mason jar or other air tight container."],"pdf":"maintenance-recipes/bbq-season-rub.pdf","img":"images/members/maintenance-recipes/bbq-season-rub.jpg","originalFile":"SOTA Maintenance Recipe BBQ Season Rub.pdf"},{"id":"baked-fish-and-veggies","title":"Baked Fish & Veggies","category":"seafood","tags":[],"servings":"Serving size based on SOTA recommended amount","ingredients":["1 lb. (16 oz) white fish","2 cups Brussel Sprouts","2 cups mushrooms","1 tbsp small capers","1/4 tsp dried thyme","2 tbsp. avocado oil","2 tbsp. butter","Salt & pepper"],"instructions":["Preheat the oven to 400 degrees.","Slice the Brussel Sprouts in half & place in a baking dish.","Drizzle with avocado oil, and season with salt & pepper.","Bake for 10-15, or until softened.","Halve or quarter the mushrooms depending on their size & fry in butter with thyme.","When mushrooms are softened, add capers and saute for 1-2 minutes. Salt & pepper to taste.","Remove the baking dish with the Brussel sprouts from the oven and spoon the mushroom/caper mixture on the top.","Season the cod pieces with salt and pepper, topped with 2 tbsp. butter and place on top of veggies.","Bake for 20 min!"],"pdf":"maintenance-recipes/baked-fish-and-veggies.pdf","img":"images/members/maintenance-recipes/baked-fish-and-veggies.jpg","originalFile":"SOTA Maintenance Recipe Baked Fish & Veggies.pdf"},{"id":"baked-pesto-salmon","title":"Baked Pesto Salmon","category":"seafood","tags":[],"servings":"Serves 2","ingredients":["1 lb. (16 oz.) salmon","2 tbsp. green pesto","salt and pepper","Green Sauce:","2 tbsp. green pesto","8 tablespoons mayonnaise","4 tablespoons greek yogurt","salt and pepper"],"instructions":["Place the salmon skin-side down in a greased baking dish.","Spread pesto on top, and salt and pepper to taste.","Bake in oven at 400°F for about 30 minutes, or until the salmon flakes easily with a fork.","Meanwhile, stir the sauce ingredients together. Pesto, mayonnaise and yogurt."],"pdf":"maintenance-recipes/baked-pesto-salmon.pdf","img":"images/members/maintenance-recipes/baked-pesto-salmon.jpg","originalFile":"SOTA Maintenance Recipe Baked Pesto Salmon.pdf"},{"id":"mouth-watering-beef-sirloin","title":"Mouth-Watering Beef Sirloin","category":"beef","tags":["grill"],"servings":"Serves 2","ingredients":["1 15-oz. beef sirloin steak","Marinade:","1/2 cup extra virgin olive oil","1 garlic clove, minced","1 shallot, minced","1 tbsp. fresh basil, minced","1 tbsp. fresh parsley, minced","1 tbsp. fresh rosemary, roughly chopped","1 tbsp. fresh thyme, roughly chopped","1 tsp. dried oregano","1 tbsp. red wine vinegar","Sea salt and freshly ground black pepper"],"instructions":["In a bowl, combine all the ingredients for the marinade and season to taste.","Pour half of the marinade into another container.","Add the steaks, and marinate for 20 minutes at room temperature.","Preheat a grill or skillet over a high heat.","Cook the steaks for 5 to 7 minutes per side for a medium-rare steak.","Spread the remaining marinade (the half that you didn't use for the steaks) over a cutting board, and press both sides of each steak onto the marinade-covered board to pick up the herbs.","Slice the steaks and serve well coated with the marinade."],"pdf":"maintenance-recipes/mouth-watering-beef-sirloin.pdf","img":"images/members/maintenance-recipes/mouth-watering-beef-sirloin.jpg","originalFile":"SOTA Maintenance Recipe Beef Sirloin.pdf"},{"id":"breakfast-for-dinner-omelet","title":"Breakfast for Dinner Omelet","category":"breakfast","tags":[],"servings":"Serves 1","ingredients":["2 eggs","2 slices bacon (uncured, cut in cubes)","1/2 cup fresh spinach","1 tbsp. fresh chives (optional)","Salt & pepper"],"instructions":["Preheat the oven to 400 degrees.","Cut bacon in small pieces and cook until crispy.","Once bacon is cooked add spinach along with chives, salt & pepper, set aside.","Lastly mix eggs in a bowl, & combine both mixtures together, adding it in a pre-greased muffin pan.","Bake for 20 minutes or until set and golden brown.","Let cool for a few minutes then serve!"],"pdf":"maintenance-recipes/breakfast-for-dinner-omelet.pdf","img":"images/members/maintenance-recipes/breakfast-for-dinner-omelet.jpg","originalFile":"SOTA Maintenance Recipe Breakfast for Dinner Omelet.pdf"},{"id":"broccoli-kale-salad","title":"Broccoli Kale Salad","category":"veggies","tags":["salad"],"servings":"Serves 2","ingredients":["1/2 cup mayo","1 tablespoon mustard","4 eggs","2 cups broccoli","1 cup kale","2 scallions","2 tablespoons olive oil","2 garlic cloves","2 avocados","1 pinch chili flakes","salt or pepper to taste"],"instructions":["Mix mayo and mustard in a small bowl and set aside.","Boil the eggs any way you like them - soft, medium or hard-boiled.","Immediately, place them in ice cold water when they're done to make them easier to peel. When cooled - divide into halves or quarters.","Split the avocados, remove the pit and cut in slices.","Slice the garlic thinly. Heat the oil in a frying pan and carefully fry the slices.","Remove the garlic from the pan and place on a paper towel to crisp up. Save the oil in the pan.","Chop broccoli and kale coarsely. Add a knob of butter to the garlic-infused oil in the pan and fry the vegetables for a couple of minutes on medium high heat until slightly softened.","Season with salt and pepper and plate with avocado, eggs and the mustard mayo.","Finish the dish with fried garlic slices for extra flavor and crunch."],"pdf":"maintenance-recipes/broccoli-kale-salad.pdf","img":"images/members/maintenance-recipes/broccoli-kale-salad.jpg","originalFile":"SOTA Maintenance Recipe Broccoli Kale Salad.pdf"},{"id":"buffalo-drum-sticks","title":"Buffalo Drum Sticks","category":"chicken","tags":["spicy"],"servings":"Serves 2","ingredients":["16-23 oz. chicken drumsticks or chicken wings","1 tablespoon olive oil or coconut oil","1 tablespoon white wine vinegar","1/2 tablespoon tomato paste","1/2 teaspoon salt","1/2 teaspoon paprika powder","1/2 tablespoon tabasco","butter or olive oil, for greasing the baking dish","Chili aioli:","5 1/3 tablespoons mayo (Primal Kitchen)","1/2 tablespoon smoked paprika powder or smoked chili powder","1/2 garlic clove, minced"],"instructions":["Preheat the oven to 450 degrees.","Put the drumsticks in a plastic bag.","Mix the ingredients for the marinade in a small bowl and pour into the plastic bag.","Shake the bag thoroughly and let marinate for 10 minutes in room temperature.","Coat a baking dish with oil.","Place the drumsticks in the baking dish and let bake for 30-40 minutes or until they are done and have turned a nice color.","Mix together mayo, garlic and chili."],"pdf":"maintenance-recipes/buffalo-drum-sticks.pdf","img":"images/members/maintenance-recipes/buffalo-drum-sticks.jpg","originalFile":"SOTA Maintenance Recipe Buffalo Drum Sticks.pdf"},{"id":"cabbage-wedge","title":"Cabbage Wedge","category":"veggies","tags":[],"servings":"Serves 2","ingredients":["1 lb Cabbage","2 2/3 oz of butter","3/4 teaspoon salt","1/8 black pepper"],"instructions":["Preheat the oven to 400-450°F.","Melt the butter in a sauce pan over low-medium heat.","Split the green cabbage into wedges and remove the thick stem in the middle.","Cut slices less than an inch thick and place on a baking sheet.","Salt and pepper and pour the melted butter on top.","Bake for 20 minutes or until the cabbage is roasted."],"pdf":"maintenance-recipes/cabbage-wedge.pdf","img":"images/members/maintenance-recipes/cabbage-wedge.jpg","originalFile":"SOTA Maintenance Recipe Cabbage Wedge.pdf"},{"id":"caribbean-pork-chops","title":"Caribbean Pork Chops","category":"pork","tags":["grill","spicy"],"servings":"Serves 2","ingredients":["2 6-oz. center-cut pork chops","1 mango, peeled, pitted, and diced","1/2 cup cherry tomatoes, quartered","2 tbsp fresh cilantro, chopped","2 tsp red wine vinegar","1 tsp extra virgin olive oil","For the rub:","1 tbsp dried thyme","1 tsp ground allspice","1/2 tsp ground coriander","1/2 tsp salt","1/8 tsp cayenne","Pinch of nutmeg","Pinch of ground cloves"],"instructions":["Combine the ingredients for the spice rub in a small bowl and stir.","Rub into the pork chops and set aside.","Add the mango, tomatoes, cilantro, red wine vinegar, and olive oil to a small bowl and toss to combine. Set aside.","Heat the grill to medium-high and cook the pork for 3-4 minutes per side, or until cooked through.","Serve warm topped with mango salsa."],"pdf":"maintenance-recipes/caribbean-pork-chops.pdf","img":"images/members/maintenance-recipes/caribbean-pork-chops.jpg","originalFile":"SOTA Maintenance Recipe Carribean Pork Chops.pdf"},{"id":"tasty-cauliflower-rice","title":"Tasty Cauliflower Rice","category":"veggies","tags":["low-carb"],"servings":"Serves 2","ingredients":["3/4 lb cauliflower","1/4 tsp salt","1/4 teaspoon turmeric","1 2/3 oz. butter (or coconut oil)"],"instructions":["Using a grater or grater attachment on a food processor, shred the entire cauliflower head.","Melt butter (or coconut oil) in a skillet.","Add the cauliflower and cook over medium heat for 5-10 minutes or until the riced cauliflower has softened a bit.","Add salt and the turmeric while frying."],"pdf":"maintenance-recipes/tasty-cauliflower-rice.pdf","img":"images/members/maintenance-recipes/tasty-cauliflower-rice.jpg","originalFile":"SOTA Maintenance Recipe Cauliflower Rice.pdf"},{"id":"chimichurri-shrimp-zoodles","title":"Chimichurri Shrimp Zoodles","category":"seafood","tags":["grill","low-carb"],"servings":"Serves 2","ingredients":["1/2 lemon (both zest & juice)","1 tsp red chili pepper","1 yellow bell pepper","2 tbsp. parsley","1 pressed garlic clove","1/3 cup avocado oil","Salt & Pepper","2 zucchini","16 peeled raw shrimp (8 per person)","1 lime for serving (optional)","1 tbsp. avocado oil"],"instructions":["Start by making the chimichurri. Rinse the lemon and remove the peel with fine grater.","Juice lemon and add both the zest and juice to a blender.","Slice the chili in half and remove seeds. Chop finely & add to blender.","Add the bell pepper, parsley, garlic, avocado oil. Season with salt and pepper. Blend until coarse.","Next, prepare the zoodles by slicing or spiraling the zucchini. Zoodles can be served raw or quickly sauteed in olive oil.","Put shrimp on a skewer and brush them with the avocado oil.","Grill or pan fry the shrimp for a couple of minutes on each side until a nice pink color. Grill the lime halves along side shrimp.","Toss the zoodles with most of the chimichurri.","Serve the skewered shrimp on the bed of zoodles, & top with remaining chimichurri dressing!"],"pdf":"maintenance-recipes/chimichurri-shrimp-zoodles.pdf","img":"images/members/maintenance-recipes/chimichurri-shrimp-zoodles.jpg","originalFile":"SOTA Maintenance Recipe Chimichurri Shrimp Zoodles.pdf"},{"id":"coconut-almond-fat-bombs","title":"Coconut Almond Fat Bombs","category":"snack","tags":["low-carb"],"servings":"","ingredients":["50g (~1.7 ounces) unsalted butter","400g (~14 ounces) ricotta","1 scoop stevia","1 tbsp psyllium husk","1/3 cup shredded coconut","3/4 tsp cardamom","1/2 tsp unsweetened vanilla extract","For rolling:","Coconut oil","Almonds","Spare shredded coconut"],"instructions":["Place a saucepan on a very low heat on the stovetop with unsalted butter in it.","Once butter is melted add the ricotta and stir until the ricotta melts into the butter.","Add in a scoop (the tiny scoop it comes with, or a 1g sachet, not a spoon-worth) of stevia and 1/3 cup of shredded coconut (1/2 at a time is easiest) and mix through the ricotta.","Add psyllium husk and mix through.","Add in cardamom and vanilla extract and mix well until the ingredients start to form a 'dough ball'.","Turn off the stove and allow the mixture to cool for approximately 10 minutes before handling.","While the mixture is cooling set up a tray to place the finished fat bombs on. A tray or plate with baking paper on top will do just fine (just make sure it can fit in your fridge).","Once the mixture has cooled enough to handle place some coconut oil on your fingertips (so the mixture doesn't get stuck to your fingers) and roll a small amount into a ball and press an almond inside.","You can then roll this ball mixture into shredded coconut and place it onto the plate.","These will store in the fridge for approximately 1 week, or longer in the freezer."],"pdf":"maintenance-recipes/coconut-almond-fat-bombs.pdf","img":"images/members/maintenance-recipes/coconut-almond-fat-bombs.jpg","originalFile":"SOTA Maintenance Recipe Coconut Almond Fat Bombs.pdf"},{"id":"colorful-veggies","title":"Colorful Veggies","category":"veggies","tags":[],"servings":"Serves 2","ingredients":["1/3 lb Brussels sprouts","2 2/3 oz. cherry tomatoes (optional)","2 2/3 oz. mushrooms","1/3 teaspoon sea salt","1/6 teaspoon ground black pepper","1/3 teaspoon dried rosemary or dried thyme","2 2/3 tablespoons olive oil"],"instructions":["Preheat the oven to 400°F.","Rinse the vegetables and peel the outer layer of the Brussels sprouts if needed.","Cut the vegetables so they're roughly the same size and place them in a baking dish.","Add spices and pour olive oil on top and mix.","Bake for 20 minutes or until the vegetables have turned a nice color."],"pdf":"maintenance-recipes/colorful-veggies.pdf","img":"images/members/maintenance-recipes/colorful-veggies.jpg","originalFile":"SOTA Maintenance Recipe Colorful Veggies.pdf"},{"id":"creamy-fish-and-broccoli-casserole","title":"Creamy Fish & Broccoli Casserole","category":"seafood","tags":[],"servings":"Serves 2","ingredients":["1 tablespoon olive oil","2 cups broccoli","3 scallions","1 tablespoon small capers","2 tbsp butter, for greasing the casserole dish","1 lb (16 oz.) white fish, in serving-sized pieces","2/3 cup heavy whipping cream","1 tablespoon Dijon mustard","1 teaspoon salt","1 teaspoon ground black pepper","1 tablespoon dried parsley","1 tbsp butter"],"instructions":["Preheat the oven to 400°F.","Divide the broccoli into small florets, including the stem.","Fry broccoli in oil on medium high for 5 minutes, until golden and soft. Season with salt and pepper.","Add scallions, finely chopped, and the capers. Fry for another 1-2 minutes and place the vegetables in a greased baking dish.","Nestle the fish in amongst the vegetables.","Mix parsley, whipping cream and mustard. Pour over the fish and vegetables.","Top with slices of butter.","Bake for 20 minutes."],"pdf":"maintenance-recipes/creamy-fish-and-broccoli-casserole.pdf","img":"images/members/maintenance-recipes/creamy-fish-and-broccoli-casserole.jpg","originalFile":"SOTA Maintenance Recipe Creamy Fish & Broccoli Casserole.pdf"},{"id":"delicious-salsa-verde","title":"Delicious Salsa Verde","category":"sauces","tags":[],"servings":"Serves 2","ingredients":["1/4 cup finely chopped fresh parsley","1 1/2 tablespoons finely chopped fresh basil or fresh cilantro","1 crushed garlic clove","1/4 lemon, the juice","1 tablespoon small capers","2/5 cup olive oil","1/2 teaspoon sea salt","1/4 teaspoon ground black pepper"],"instructions":["Add all of the ingredients to a deep bowl and mix with a blender until the sauce has the desired consistency.","Store the sauce in the refrigerator for up to 4-5 days or in the freezer."],"pdf":"maintenance-recipes/delicious-salsa-verde.pdf","img":"images/members/maintenance-recipes/delicious-salsa-verde.jpg","originalFile":"SOTA Maintenance Recipe Delicious Salsa Verde.pdf"},{"id":"fiesta-eggs","title":"Fiesta Eggs","category":"breakfast","tags":["spicy"],"servings":"Serves 2","ingredients":["3 eggs","1/2 - 1 scallion","1 - 1 1/2 pickled jalapenos, finely chopped","1/2 tomato, finely chopped","1 tablespoon butter, for frying","salt and pepper"],"instructions":["Finely chop the scallions & jalapenos.","Fry in butter for 3 minutes on medium heat.","Beat the eggs and pour into the pan and add tomatoes.","Scramble for 2 minutes.","Then add the seasoning."],"pdf":"maintenance-recipes/fiesta-eggs.pdf","img":"images/members/maintenance-recipes/fiesta-eggs.jpg","originalFile":"SOTA Maintenance Recipe Fiesta Eggs.pdf"},{"id":"finger-licking-pulled-pork","title":"Finger Licking Pulled Pork","category":"pork","tags":["crock-pot","spicy"],"servings":"Serves 2","ingredients":["1/2 tablespoon cacao nibs or cacao powder","1 teaspoon ground black pepper","1 teaspoon paprika powder","1 teaspoon ground ginger","1/2 tablespoon salt","1 teaspoon anise seeds or fennel seeds","1 teaspoon cayenne pepper","1 tablespoon olive oil","1 lb (16 oz.) tenderloin, whole"],"instructions":["Grind the spices and cacao nibs in a food processor or a coffee grinder.","Mix ground spices with the olive oil and spread all over the surface of the pork.","Salt the seasoned meat and put it in a slow cooker.","Cook for five hours on low heat or four on medium heat.","Remove the pork from the slow cooker and pull the meat apart using two forks.","Serve with sliced red onion, sliced pickles, lettuce!"],"pdf":"maintenance-recipes/finger-licking-pulled-pork.pdf","img":"images/members/maintenance-recipes/finger-licking-pulled-pork.jpg","originalFile":"SOTA Maintenance Recipe Finger Licking Pulled Pork.pdf"},{"id":"fresh-greek-salad","title":"Fresh Greek Salad","category":"veggies","tags":["salad"],"servings":"Serves 2","ingredients":["3 tomatoes","1 cucumber","1 red onion","1 green bell pepper","1/2 cup feta cheese","10 black greek olives","4 tablespoons extra virgin olive oil","1 tablespoon red wine vinegar","salt and pepper","2 teaspoons dried oregano"],"instructions":["Cut the tomatoes and cucumber into bite-sized pieces.","Thinly slice the bell pepper and the onion.","Arrange on a serving platter or, if possible, plate the salad on individual salad plates.","Add feta cheese and olives, and drizzle olive oil and vinegar over the salad.","Season with salt and pepper according to taste.","Sprinkle with crumbled oregano and serve."],"pdf":"maintenance-recipes/fresh-greek-salad.pdf","img":"images/members/maintenance-recipes/fresh-greek-salad.jpg","originalFile":"SOTA Maintenance Recipe Fresh Greek Salad.pdf"},{"id":"fresh-grilled-salmon","title":"Fresh Grilled Salmon","category":"seafood","tags":["grill"],"servings":"Serves 2","ingredients":["2 cups broccoli","2 tbsp. butter","Salt & pepper to taste","1 lb. (16 oz.) salmon","1/2 lime (optional)"],"instructions":["Cut the broccoli into smaller florets and let simmer in lightly salted water for a couple of minutes.","Make sure the broccoli maintains its chewy texture and delicate color.","Once broccoli is drained, add butter and pepper to taste.","Fry the salmon in butter, a few minutes on each side.","The lime can be fried in the same pan or be served raw. This step can also be made on an outdoor grill.","Once cooked serve salmon on bed of broccoli and enjoy!"],"pdf":"maintenance-recipes/fresh-grilled-salmon.pdf","img":"images/members/maintenance-recipes/fresh-grilled-salmon.jpg","originalFile":"SOTA Maintenance Recipe Fresh Grilled Salmon.pdf"},{"id":"yummy-garlic-chicken","title":"Yummy Garlic Chicken","category":"chicken","tags":[],"servings":"Serves 2","ingredients":["1 lb chicken thighs","1 tablespoon olive oil","2 1/2 - 5 garlic cloves, sliced","1/2 lemon, the juice","4 tablespoons fresh parsley, finely chopped","2 tablespoons butter"],"instructions":["Preheat the oven to 450°F.","Place the chicken pieces in a butter-greased baking pan.","Salt and pepper generously.","Sprinkle the garlic and parsley over the chicken pieces, and drizzle the lemon juice and olive oil on top.","Bake the chicken until golden and the garlic slices have turned brown and roasted, about 30-40 minutes, depending on how large the pieces are.","Lower the temperature a little towards the end."],"pdf":"maintenance-recipes/yummy-garlic-chicken.pdf","img":"images/members/maintenance-recipes/yummy-garlic-chicken.jpg","originalFile":"SOTA Maintenance Recipe Garlic Chicken.pdf"},{"id":"greek-season-rub","title":"Greek Season Rub","category":"sauces","tags":[],"servings":"Serves 2","ingredients":["1 Tbsp. Kosher salt","2 tsp dried basil","4 tsp oregano","1 tsp dried thyme","4 tsp onion powder","4 tsp garlic powder","2 tsp onion flakes","2 tsp dried dill","2 tsp pepper","2 tsp parsley","2 tsp rosemary","1 tsp cinnamon","1 tsp nutmeg"],"instructions":["Mix all spices together.","Store in a pint sized mason jar or other air tight container."],"pdf":"maintenance-recipes/greek-season-rub.pdf","img":"images/members/maintenance-recipes/greek-season-rub.jpg","originalFile":"SOTA Maintenance Recipe Greek Season Rub.pdf"},{"id":"ground-beef-hamburger-patties","title":"Ground Beef Hamburger Patties","category":"beef","tags":["grill"],"servings":"Serving size based on SOTA recommended amount","ingredients":["1 lb. (16 oz.) ground beef","1 egg","1 teaspoon salt","1 teaspoon black pepper","1 teaspoon parsley","1 tablespoon avocado oil","1 tablespoon butter"],"instructions":["Mix all the ingredients for the hamburgers and form patties.","Fry over medium-high heat in a pan with both butter and extra virgin olive oil for at least 10 minutes or until the patties have turned nice color!","Patties can also be made on the grill if preferred!"],"pdf":"maintenance-recipes/ground-beef-hamburger-patties.pdf","img":"images/members/maintenance-recipes/ground-beef-hamburger-patties.jpg","originalFile":"SOTA Maintenance Recipe Ground Beef Hamburger Patties.pdf"},{"id":"indian-spice-fried-cabbage-rice","title":"Indian Spice Fried Cabbage Rice","category":"pork","tags":["spicy","low-carb"],"servings":"Serves 2","ingredients":["2 cups green cabbage","4 tbsp butter","1 lb. (16 oz) ground pork","1/2 tsp salt","1/2 tsp onion powder","1/8 tsp black pepper","1/2 tbsp. apple cider vinegar","1/2 tbsp. red curry paste","1/4 yellow onion (chopped)","4 tbsp. cilantro (chopped)","2 tbsp. mayo (Primal Kitchen)"],"instructions":["Shred the cabbage with a knife or food processor as finely as possible.","Fry the cabbage in half of the butter in a large frying pan on medium heat. Add spices and vinegar. Saute until fragrant.","Place cabbage in a bowl and reserve.","Melt the remaining butter in same pan and add garlic, onion, curry paste and cook for 1 min.","Add ground meat and cook until most of the liquid from the meat is evaporated.","Lower heat and add cabbage into pan. Stir until everything is warmed through & season with salt & pepper.","Garnish with cilantro and a dollop of mayo!"],"pdf":"maintenance-recipes/indian-spice-fried-cabbage-rice.pdf","img":"images/members/maintenance-recipes/indian-spice-fried-cabbage-rice.jpg","originalFile":"SOTA Maintenance Recipe Indian Spice Fried Cabbage Rice.pdf"},{"id":"loaded-zucchini-skins","title":"Loaded Zucchini Skins","category":"veggies","tags":["low-carb"],"servings":"","ingredients":["1/2 lb. of bacon","4 large zucchinis","2 tbsp. of avocado oil","1/2 tsp of chili powder","1/2 tsp cumin","2 cups shredded cheddar","1 cup full fat sour cream","2 green onions, sliced","Sea salt"],"instructions":["Preheat the oven to 400 degrees.","Cook the bacon in a medium skillet about 8-10 minutes, then transfer to a paper towel to drain and chop into smaller pieces.","Cut zucchinis in half, lengthwise. Spoon out the center of the zucchinis, then cut each piece to make 3 pieces.","Transfer zucchinis to a large baking sheet and toss with avocado oil. Season with chili powder, cumin, sea salt, and pepper.","Bake until slightly tender, about 5 minutes.","Top each piece of zucchini with cheese and bacon.","Return to oven and bake until cheese is bubbly and zucchini is tender, about 10 minutes.","Garnish with sour cream and green onions once they are finished cooking.","And Enjoy!"],"pdf":"maintenance-recipes/loaded-zucchini-skins.pdf","img":"images/members/maintenance-recipes/loaded-zucchini-skins.jpg","originalFile":"SOTA Maintenance Recipe Loaded Zucchini Skins.pdf"},{"id":"low-carb-burger-and-salsa","title":"Low Carb Burger & Salsa","category":"beef","tags":["low-carb","grill"],"servings":"Serves 2","ingredients":["3/4 lb ground beef","1 teaspoon garlic powder","1 teaspoon onion powder","1 teaspoon paprika powder","1 tablespoon fresh oregano, finely chopped","1/2 oz. butter","1 tomato","1 scallion","1/2 avocado","1/2 tablespoon olive oil","Salt","Cilantro"],"instructions":["Chop up the salsa ingredients and stir together in a small bowl. Put aside.","Mix in seasoning into the ground beef.","Make four burgers and fry in a pan or grill if you prefer.","Serve on lettuce with a nice juicy dill pickle!"],"pdf":"maintenance-recipes/low-carb-burger-and-salsa.pdf","img":"images/members/maintenance-recipes/low-carb-burger-and-salsa.jpg","originalFile":"SOTA Maintenance Recipe Low Carb Burger & Salsa.pdf"},{"id":"low-carb-cauliflower-wedge","title":"Low Carb Cauliflower Wedge","category":"veggies","tags":["low-carb","spicy"],"servings":"Serves 2","ingredients":["1/3 cauliflower","1 garlic clove, finely chopped","1 tablespoon fresh ginger, finely chopped","1 teaspoon onion powder","1 tablespoon curry powder or Turmeric","1 lemon (the juice)","1/3 teaspoon sea salt","3 tablespoons greek yogurt or coconut milk","1 tablespoon fresh parsley or fresh cilantro, finely chopped","1 tablespoon melted butter or olive oil"],"instructions":["Put the cauliflower head in a plastic bag.","Mix together lemon juice, spices & yogurt (or coconut milk). Pour over the cauliflower and let sit in the refrigerator for at least an hour, or overnight.","Preheat the oven to 350 degrees F.","Remove the cauliflower from the plastic bag and place in a baking dish.","Bake in the oven for about 45-60 minutes or until the cauliflower is soft inside and has a nice color on the outside.","Pour melted butter or oil on top, and sprinkle finely chopped cilantro or parsley at the time of serving."],"pdf":"maintenance-recipes/low-carb-cauliflower-wedge.pdf","img":"images/members/maintenance-recipes/low-carb-cauliflower-wedge.jpg","originalFile":"SOTA Maintenance Recipe Low Carb Cauliflower Wedge.pdf"},{"id":"low-carb-cheesy-bell-peppers","title":"Low Carb Cheesy Bell Peppers","category":"veggies","tags":["low-carb"],"servings":"Serves 2","ingredients":["4 bell peppers, about 2 per serving","1/2 cup cream cheese","1/2 oz. chorizo, thinly sliced","1 teaspoon mild chipotle paste","1 tablespoon olive oil","1 tablespoon fresh thyme or fresh cilantro","8 tablespoons shredded cheese"],"instructions":["Set the oven to 400 degrees F.","Split the bell peppers lengthwise and remove the core.","Chop the sausage and the herbs finely.","Mix together cheese, spices and oil in a small bowl. Add the sausage and herbs. Stir until smooth.","Add the batter to the bell peppers and place in a greased baking dish.","Sprinkle shredded cheese on top.","Bake in the oven for 15-20 minutes or until the cheese melts and begins to brown."],"pdf":"maintenance-recipes/low-carb-cheesy-bell-peppers.pdf","img":"images/members/maintenance-recipes/low-carb-cheesy-bell-peppers.jpg","originalFile":"SOTA Maintenance Recipe Low Carb Cheesy Bell Peppers.pdf"},{"id":"low-carb-chicken-and-veggie-zoodles","title":"Low Carb Chicken & Veggie Zoodles","category":"chicken","tags":["low-carb"],"servings":"Serves 2","ingredients":["1 tablespoon coconut oil","2 cups broccoli","1/2 yellow onion","1 lb (16 oz.) cooked chicken breasts or turkey","1 cup coconut milk or coconut cream","1 tablespoon green curry paste","1 tablespoon peanut butter","Salt and pepper","2 tablespoons salted peanuts, for decoration"],"instructions":["Peel the onion and cut into thin, uneven wedges.","Peel the lower part of the broccoli stem with a potato peeler or a small sharp knife. Cut into thin rods lengthwise so that the florets and the stem are still joined together.","Heat a generous amount of oil in wok pan or a saute pan. Saute broccoli and onion on high heat while stirring for a few minutes. It's ok if it gets a little brown here and there - will give a nice flavor - but the vegetables should still be crispy. Salt and pepper.","Slice or dice the chicken meat and add to the pan.","Add coconut milk, curry paste and peanut butter and stir. Let simmer for a few minutes to make the flavors come out.","Salt to taste. Add the peanuts just before serving!","Serve with zoodles."],"pdf":"maintenance-recipes/low-carb-chicken-and-veggie-zoodles.pdf","img":"images/members/maintenance-recipes/low-carb-chicken-and-veggie-zoodles.jpg","originalFile":"SOTA Maintenance Recipe Low Carb Chicken & Veggie Zoodles.pdf"},{"id":"low-carb-smoothie","title":"Low Carb Smoothie","category":"breakfast","tags":["low-carb"],"servings":"Serves 2","ingredients":["6 tablespoons coconut milk or coconut cream","2/3 cup water","1-2 tablespoons lime juice","1 handful of spinach","2 teaspoons fresh ginger, grated"],"instructions":["Mix all ingredients together.","Start with 1 tablespoon lime and increase the amount to taste.","Sprinkle with some grated ginger and serve."],"pdf":"maintenance-recipes/low-carb-smoothie.pdf","img":"images/members/maintenance-recipes/low-carb-smoothie.jpg","originalFile":"SOTA Maintenance Recipe Low Carb Smoothie.pdf"},{"id":"low-carb-taco-chips","title":"Low Carb Taco Chips","category":"snack","tags":["low-carb","spicy"],"servings":"Serves 1","ingredients":["1 large zucchini","Salt","2 tbsp. avocado oil","1 tbsp. chili powder","2 tsp paprika","2 tsp ground cumin","1 tsp garlic powder","1 tsp onion powder","1/2 tsp chili flakes","1/2 tsp oregano","1/2 tsp pepper","1 pinch cinnamon","1 tbsp. salt (optional)"],"instructions":["Cut the zucchini crosswise into thin, round, slices.","Sprinkle with lots of salt. Let sit for 5 minutes, then press out water.","Heat the avocado oil in fryer or skillet to 350 degrees.","Drop the sliced zucchini into the hot oil, working in batches at a time.","Once the zucchini turns golden brown, remove from fryer and place onto a paper towel.","Sprinkle with taco seasoning and enjoy!"],"pdf":"maintenance-recipes/low-carb-taco-chips.pdf","img":"images/members/maintenance-recipes/low-carb-taco-chips.jpg","originalFile":"SOTA Maintenance Recipe Low Carb Taco Chips.pdf"},{"id":"low-carb-turkey-burgers","title":"Low Carb Turkey Burgers","category":"chicken","tags":["low-carb","grill"],"servings":"Makes 4-6 burgers","ingredients":["1 lb. ground turkey","1 tsp onion powder","1 tsp paprika","1/2 tsp salt","1/2 tsp freshly ground pepper","1/2 tsp coriander","Pinch of cayenne","2 green onions, chopped","1 tomato, sliced","2 cups fresh spinach or arugula","1 avocado, sliced"],"instructions":["Add the ground turkey, onion powder, paprika, salt, pepper, coriander, cayenne, and green onions to a large bowl and stir to combine.","Heat the grill to medium-high heat and cook the burgers for 5-6 minutes on each side, or until cooked through.","Serve the burgers over sliced tomato, spinach, and avocado."],"pdf":"maintenance-recipes/low-carb-turkey-burgers.pdf","img":"images/members/maintenance-recipes/low-carb-turkey-burgers.jpg","originalFile":"SOTA Maintenance Recipe Low Carb Turkey Burgers.pdf"},{"id":"marinated-grilled-shrimp","title":"Marinated Grilled Shrimp","category":"seafood","tags":["grill","spicy"],"servings":"Serves 2","ingredients":["1/3 cup Extra Virgin Olive Oil","1 Tablespoon parsley (chopped)","3/8 Lemon (juiced)","2 teaspoons hot sauce","1 clove garlic (minced)","1 teaspoon tomato paste","3/4 teaspoon dried oregano","1/4 teaspoon salt","1/4 teaspoon pepper","5-8 shrimp per person"],"instructions":["In a mixing bowl, mix together olive oil, parsley, lemon juice, hot sauce, garlic, tomato paste, oregano, salt, and black pepper.","Reserve a small amount for basting later.","Pour remaining marinade into a large re-sealable plastic bag with shrimp. Seal, and marinate in the refrigerator for 2 hours.","Preheat grill for medium-low heat.","Thread shrimp onto skewers.","Cook shrimp for 5 minutes per side, frequently basting with reserved marinade."],"pdf":"maintenance-recipes/marinated-grilled-shrimp.pdf","img":"images/members/maintenance-recipes/marinated-grilled-shrimp.jpg","originalFile":"SOTA Maintenance Recipe Marinated Grilled Shrimp.pdf"},{"id":"mavs-crunchy-eggplant-sticks","title":"Mavs Crunchy Eggplant Sticks","category":"veggies","tags":[],"servings":"","ingredients":["1 medium eggplant","1 cup almond flour","1/2 cup parmesan cheese","Sea salt","1 egg white","Cooking spray","1 cup full fat greek yogurt","1/2 teaspoon garlic powder","1/2 teaspoon dried parsley","1/2 teaspoon dried thyme","1/2 teaspoon sea salt","Freshly ground black pepper"],"instructions":["Heat the oven and prepare the baking sheet. Preheat the oven to 425 degrees. Line a baking sheet with foil and spray with cooking spray or rub with a little avocado oil.","Cut the eggplant. Peel eggplant and cut into french-fry shapes, about 1-inch-thick.","Season. Place the eggplant in a large bowl, sprinkle with the salt, and toss to combine.","Prepare the cheese mix. Combine the almond flour and parmesan cheese in a gallon-sized plastic bag. In a small bowl mix the egg white with a fork until the egg turns foamy. Set aside.","Dip the eggplant sticks in egg white. Dip eggplant sticks into the egg white and turn to coat, do this with all sticks then place into gallon bag with the cheese mixture.","Coat the eggplant fries. Seal the bag and shake to evenly coat the eggplant fries with the cheese mixture.","Roast. Remove the eggplant sticks from the bag, gently shaking off excess crumbs, and place in a single layer on the prepared baking sheet. Spray with another coat of cooking spray. Sprinkle with more salt. Roast, flipping the sticks every 5 minutes, until golden-brown and crisp, about 15 minutes total.","Make the yogurt dip. While the eggplant fries are roasting, place the yogurt, garlic powder, dried parsley, dried thyme, salt, and pepper in a small bowl and whisk to combine. Serve the yogurt dip with the warm eggplant sticks."],"pdf":"maintenance-recipes/mavs-crunchy-eggplant-sticks.pdf","img":"images/members/maintenance-recipes/mavs-crunchy-eggplant-sticks.jpg","originalFile":"SOTA Maintenance Recipe Mavs Crunchy Eggplant Sticks.pdf"},{"id":"mavs-game-day-cheeseburger-salad","title":"Mavs Game Day Cheeseburger Salad","category":"beef","tags":["salad"],"servings":"Serves 2-3","ingredients":["16 oz (1 lb) grass-fed ground beef","2 Tbsp taco seasoning","2 Tbsp water","3 Romaine lettuce spears or one head iceberg lettuce","1 cup tomatoes (chopped)","3/4 cup cheddar cheese, full fat (shredded)","1/2 cup pickles (diced)","1 avocado, diced","1/2 cup mayonnaise, full fat","2 Tbsp pickles diced or relish","2 tsp mustard","1 tsp white vinegar","1/2 tsp smoked paprika","1/4 tsp liquid stevia (or to taste)"],"instructions":["Cook ground beef, water and taco seasoning in a pan over medium high heat. Stir while breaking up the pieces with a wooden spoon, for about 7-10 minutes until the beef is browned and pink is gone. Set aside.","Meanwhile, mix in a bowl or blend all the dressing ingredients except the stevia. If dressing is thicker than you like, thin out with a little water. Add 1/2 the stevia sweetener and continue adding till taste is perfect. Refrigerate until ready to serve.","Combine the remaining salad ingredients in a large bowl. Add the ground beef. Toss with dressing."],"pdf":"maintenance-recipes/mavs-game-day-cheeseburger-salad.pdf","img":"images/members/maintenance-recipes/mavs-game-day-cheeseburger-salad.jpg","originalFile":"SOTA Maintenance Recipe Mavs Game Day Cheeseburger Salad.pdf"},{"id":"mavs-game-day-jalapeno-poppers","title":"Mavs Game Day Jalapeno Poppers","category":"snack","tags":["spicy"],"servings":"","ingredients":["8 oz cream cheese","1/2 cup shredded sharp cheddar","1 tsp pink Himalayan salt","1/2 tsp black pepper","8-12 jalapenos, halved, de-seeded","8 slices of Pedersons bacon, cut in half"],"instructions":["Preheat oven to 375 degrees and line baking sheet with parchment paper or foil.","Place bacon slices on paper towel-lined plate and microwave for 3 minutes. Set aside to slightly cool.","In a medium bowl, add cream cheese, shredded sharp cheddar, salt, and pepper and microwave for 15 seconds. Stir together.","Carefully scoop cream cheese mixture into plastic baggie. With a scissors, snip off corner of baggie and pipe contents into jalapenos.","Wrap bacon slices around jalapenos and pin with toothpick.","Place jalapenos on prepared baking sheet and bake for 15 minutes.","Increase oven heat to broil and broil for 2-3 minutes, watching to ensure cream cheese does not burn.","Remove from oven and allow to cool slightly before eating."],"pdf":"maintenance-recipes/mavs-game-day-jalapeno-poppers.pdf","img":"images/members/maintenance-recipes/mavs-game-day-jalapeno-poppers.jpg","originalFile":"SOTA Maintenance Recipe Mavs Game Day Jalapeno Poppers.pdf"},{"id":"on-the-go-salad-jars","title":"On The Go Salad Jars","category":"veggies","tags":["salad"],"servings":"Serves 2","ingredients":["1 lb. (16 oz.) protein of your choice","2 cups leafy greens","1 cup cherry tomatoes","1 cup red bell peppers","1 cup cucumber","1 scallion","8 tablespoons extra virgin olive oil","1 avocado"],"instructions":["Shred or chop veggies of your choice.","First, put dark leafy greens such as spinach or arugula at the bottom of jar. Green and red cabbage gives a great crunch.","Add sliced onion, avocado (1/2), bell peppers and tomato in layers.","Choose which protein to top your salad off, get creative with your protein choice, for example boiled eggs, tuna, chicken etc.","Lastly top your salad off with your extra virgin olive oil dressing or use our Lemony Vinaigrette dressing!"],"pdf":"maintenance-recipes/on-the-go-salad-jars.pdf","img":"images/members/maintenance-recipes/on-the-go-salad-jars.jpg","originalFile":"SOTA Maintenance Recipe On The Go Salad Jars.pdf"},{"id":"purple-cabbage-sota-salad","title":"Purple Cabbage SOTA Salad","category":"veggies","tags":["salad"],"servings":"","ingredients":["1 small head (4 cups) red cabbage, cut into thin ribbons","6 Tbsp apple cider vinegar","1/4 cup (8 Tbsp) olive oil","1/8 tsp stevia or to taste","1/8 tsp salt and pepper"],"instructions":["Prepare the red cabbage: remove the outer leaves. Cut in half. Cut out the white \"V\" shaped inner stem.","Using a very sharp knife, cut the cabbage into thin strips.","Place the cut cabbage into a deep salad bowl.","In a separate small bowl add the apple cider vinegar, olive oil, stevia, salt and pepper. Make this dressing mixture your preferred stevia sweetness.","Add the dressing mixture to the cabbage bowl.","Cover salad bowl and refrigerate for a minimum of 3-4 hours to allow the vinaigrette to marinate the cabbage. Best results are if refrigerated overnight."],"pdf":"maintenance-recipes/purple-cabbage-sota-salad.pdf","img":"images/members/maintenance-recipes/purple-cabbage-sota-salad.jpg","originalFile":"SOTA Maintenance Recipe Purple Cabbage SOTA Salad.pdf"},{"id":"quick-and-easy-lemony-vinaigrette","title":"Quick and Easy Lemony Vinaigrette","category":"sauces","tags":[],"servings":"","ingredients":["3 tbsp. fresh lime or lemon juice","1/2 tsp Organic Dijon mustard (no sugar added)","3/4 cup extra virgin olive oil","Sea salt and ground pepper to taste"],"instructions":["Combine all the ingredients except the oil.","Then add the oil slowly while whisking vigorously.","Using a blender will help to emulsify the vinaigrette.","Shake well before using."],"pdf":"maintenance-recipes/quick-and-easy-lemony-vinaigrette.pdf","img":"images/members/maintenance-recipes/quick-and-easy-lemony-vinaigrette.jpg","originalFile":"SOTA Maintenance Recipe Quick and Easy Lemony Vinaigrette.pdf"},{"id":"ranch-mix","title":"Ranch Mix","category":"sauces","tags":[],"servings":"","ingredients":["2 tsp salt","4 tbsp parsley","3 tsp dill weed","2 tsp dried chives","4 tsp garlic powder","4 tsp onion powder","4 tsp dried onion flakes","2 tsp black pepper"],"instructions":["Mix with Extra Virgin olive oil to marinade meat.","Sprinkle over veggies you are grilling or sauteing, or roasting."],"pdf":"maintenance-recipes/ranch-mix.pdf","img":"images/members/maintenance-recipes/ranch-mix.jpg","originalFile":"SOTA Maintenance Recipe Ranch Mix.pdf"},{"id":"sota-1-carb-bread","title":"SOTA 1 Carb Bread","category":"snack","tags":["low-carb"],"servings":"Makes 12 slices","ingredients":["1 1/2 cups of almond flour","1 Tbsp. baking powder","1/4 cup Kerrygold grass fed butter","6 eggs"],"instructions":["Preheat oven to 390 degrees.","Mix all ingredients together until there are no clumps.","Pour in a greased 5 x 9.5 baking tin.","Bake for 20 minutes or until a toothpick is inserted in the middle and comes out clean."],"pdf":"maintenance-recipes/sota-1-carb-bread.pdf","img":"images/members/maintenance-recipes/sota-1-carb-bread.jpg","originalFile":"SOTA Maintenance Recipe SOTA 1 Carb Bread.pdf"},{"id":"sota-cauliflower-mac-n-cheese","title":"SOTA Cauliflower Mac n Cheese","category":"veggies","tags":["low-carb"],"servings":"","ingredients":["1 large head of cauliflower (riced or chopped)","1/8 tsp garlic powder","2 tsp Dijon mustard","1/4 tsp black pepper","1/2 tsp sea salt","2 cups of full fat cheddar cheese (sharp)","2 oz. full fat cream cheese","1 cup of heavy cream"],"instructions":["Preheat oven to 375 degrees.","Bring a large pot of water to a boil, add some sea salt to the water.","Spray an 8x8 baking dish with vegetable oil spray.","Cook the cauliflower in the boiling water until crisp-tender, about 5 minutes.","Drain well and place back into the hot pot for a few minutes.","Then, transfer the cauliflower to the baking dish and set aside.","Bring the cream to a simmer in a small saucepan and whisk in the cream cheese and mustard until smooth.","Stir in 1 1/2 cups of the cheese, salt, pepper, and garlic and whisk enough until cheese melts, 1-2 minutes.","Remove from heat, pour over the cauliflower, and stir to combine.","Top with the remaining 1/2 cup of cheese and bake until browned and bubbly, about 15 minutes.","Allow to cool about 5 minutes then serve."],"pdf":"maintenance-recipes/sota-cauliflower-mac-n-cheese.pdf","img":"images/members/maintenance-recipes/sota-cauliflower-mac-n-cheese.jpg","originalFile":"SOTA Maintenance Recipe SOTA Cauliflower Mac n Cheese.pdf"},{"id":"sota-style-taco-stuffed-avocados","title":"SOTA Style Taco Stuffed Avocados","category":"beef","tags":["spicy"],"servings":"","ingredients":["6 oz ground beef","4 ounces tomato sauce","1 avocado, halved","1/4 cup shredded cheddar cheese","6 cherry tomatoes, sliced","1/4 cup lettuce, shredded","1 Tbs cilantro","Spoon full of sour cream","1 Tbsp chili powder","1/2 tsp salt","3/4 tsp cumin","1/2 tsp dried oregano","1/4 tsp garlic powder","1/4 tsp onion powder"],"instructions":["Add the ground beef to a medium size pan. Cook over medium heat until browned.","Drain the grease and add the seasonings and tomato sauce to the meat. Stir to combine. Cook for about 3-4 minutes.","Remove the pit from the halved avocados and scoop out some of the avocado to make room. Add the taco meat into the avocado and top with cheese, tomatoes, lettuce, cilantro and sour cream."],"pdf":"maintenance-recipes/sota-style-taco-stuffed-avocados.pdf","img":"images/members/maintenance-recipes/sota-style-taco-stuffed-avocados.jpg","originalFile":"SOTA Maintenance Recipe SOTA Style Taco Stuffed Avocados.pdf"},{"id":"sotas-chicken-curry-bowl","title":"SOTA's Chicken Curry Bowl","category":"chicken","tags":["spicy"],"servings":"","ingredients":["16 oz (1 pound) boneless skinless chicken thighs (around 5-6 thighs)","2 tbsp Yellow curry powder","2 tsp fresh chopped garlic","1/3 cup coconut oil or avocado oil","1/2 white onion, chopped","1 cup cauliflower","1 red bell pepper","12 oz. can unsweetened full fat coconut milk","1 tsp salt","1/4 cup fresh cilantro","Optional: 1 tsp fish sauce"],"instructions":["Cut the raw chicken into bite-sized pieces.","Using a clean cutting board and knife, cut the cauliflower and peppers into smaller pieces.","Heat up the oil in a large pan. Add curry powder and garlic. Fry for a minute to release the flavors.","Add chicken chunks and season with 1/2 tsp salt and pepper. Saute for about 5 minutes. Stir often to make sure all pieces are lightly browned and cooked through. Remove from pan.","Add cauliflower, onion and bell pepper to the same pan. Cook the vegetables on medium high heat for a few minutes till tender.","Add the full can of coconut milk and the chicken. Let simmer for about 5-10 minutes. (Add the fish sauce if using.) Season with 1/2 tsp salt and pepper to taste.","Serve with finely chopped cilantro sprinkled on top."],"pdf":"maintenance-recipes/sotas-chicken-curry-bowl.pdf","img":"images/members/maintenance-recipes/sotas-chicken-curry-bowl.jpg","originalFile":"SOTA Maintenance Recipe SOTAs Chicken Curry Bowl.pdf"},{"id":"sotas-egg-in-an-avocado","title":"SOTA's Egg in an Avocado","category":"breakfast","tags":[],"servings":"","ingredients":["1 medium avocado","2 eggs","1 piece of cooked bacon, diced","1/4 cup of cheese","2 pinches of sea salt"],"instructions":["Preheat the oven to 425 degrees.","Begin by cutting the avocado in half and removing the seed.","With a spoon, scoop out some of the avocado to make room for the egg.","Place in a muffin pan to keep the avocado stable while cooking.","Crack your egg and add it to the inside of the avocado.","Sprinkle a little cheese on top with a pinch of sea salt.","Top with the chopped bacon.","Cook for 14-16 minutes in the oven and serve warm!"],"pdf":"maintenance-recipes/sotas-egg-in-an-avocado.pdf","img":"images/members/maintenance-recipes/sotas-egg-in-an-avocado.jpg","originalFile":"SOTA Maintenance Recipe SOTAs egg in an Avocado.pdf"},{"id":"sesame-sota-zoodle-bowl","title":"Sesame SOTA Zoodle Bowl","category":"veggies","tags":["low-carb"],"servings":"Makes 4 cups of vegetables","ingredients":["2 cups Zucchini (about 2 medium zucchinis) spiralized","1 cup sliced mushrooms","1 cup shredded broccoli","1 Tbsp avocado oil","1 Tbsp sesame oil","1 Tbsp avocado oil","1/4 tsp garlic powder","1 tsp crushed red pepper","1 Tbsp Soy Sauce","1/2 tsp salt","1/2 tsp stevia"],"instructions":["Combine all sauce ingredients in a bowl. Set aside.","Make your zucchini zoodles using a vegetable spiralizer and pat them dry with a towel to remove some of the excess moisture. Set aside.","Heat 1 Tbsp of avocado oil in a large skillet on medium heat. Add the mushrooms, cook on medium heat until they begin to soften, about 3 minutes.","Once mushrooms are soft add the shredded broccoli (this can be found in a bag at the grocery store or you can chop your broccoli into small bite size pieces and grate the stem.) Cook broccoli with the mushrooms for 3-5 minutes.","Add your zucchini zoodles and the sauce mix to the pan with the other vegetables.","Heat evenly by gently turning the zoodles with a fork or tongs until the noodles become soft but not soggy. This takes about 3-5 minutes."],"pdf":"maintenance-recipes/sesame-sota-zoodle-bowl.pdf","img":"images/members/maintenance-recipes/sesame-sota-zoodle-bowl.jpg","originalFile":"SOTA Maintenance Recipe Sesame SOTA Zoodle Bowl.pdf"},{"id":"slow-cooked-moroccan-beef","title":"Slow Cooked Moroccan Beef","category":"beef","tags":["crock-pot"],"servings":"Serves 2 (8 oz serving)","ingredients":["2 tablespoons sliced onions","1 lb. (16 oz.) beef roast","1 tablespoon garam masala seasoning","1 tbsp sea salt"],"instructions":["Slice the onion into thin strings. Place into the slow cooker.","Put beef roast into the cooker on top of onions.","Add spices and salt.","Cook on low heat for 8 hours.","Shred with a fork and cook on lower setting allowing spices to marinate beef!"],"pdf":"maintenance-recipes/slow-cooked-moroccan-beef.pdf","img":"images/members/maintenance-recipes/slow-cooked-moroccan-beef.jpg","originalFile":"SOTA Maintenance Recipe Slow Cooked Moroccan Beef.pdf"},{"id":"southern-tofu-scramble","title":"Southern Tofu Scramble","category":"breakfast","tags":["spicy"],"servings":"Serving size based on SOTA recommended amount","ingredients":["1/2 lb (8 oz.) extra firm tofu","1-2 tbsp. avocado oil","1/2 red onion (sliced)","1/2 red pepper (thinly sliced)","2 cups kale (chopped)","1/2 tsp salt","1/2 tsp garlic powder","1/2 tsp cumin powder","1/4 chili powder","Water to thin","1/4 tsp turmeric (optional)","Hot sauce (optional)","Cilantro (optional)"],"instructions":["Pat tofu dry and roll in a clean, absorbent towel with something heavy on top, such as a skillet for 15 min.","While tofu is draining, prepare sauce by adding dry spices to small bowl and adding enough water to make a pourable sauce. Set aside.","Prep veggies and warm a large skillet over medium heat. Once hot, add 1-2 tbsp. avocado oil and the onion and red pepper. Season with a pinch each salt and pepper and stir. Cook until softened, about 5 min.","Add kale, season with a bit more salt and pepper, and cover to steam for 2 minutes.","In the meantime, unwrap tofu and use a fork to crumble into bite sized pieces.","Use a spatula to move the veggies to one side of pan and add tofu. Saute for 2 min then add sauce, pouring it mostly over the tofu and a little over the veggies.","Stir immediately evenly. Cook for another 5-7 min until tofu is slightly browned!"],"pdf":"maintenance-recipes/southern-tofu-scramble.pdf","img":"images/members/maintenance-recipes/southern-tofu-scramble.jpg","originalFile":"SOTA Maintenance Recipe Southern Tofu Scramble.pdf"},{"id":"sotas-spicy-chicken-wraps","title":"SOTA's Spicy Chicken Wraps","category":"chicken","tags":["spicy"],"servings":"Makes 6-8 wraps","ingredients":["2 tbsp extra virgin olive oil","1 lb. boneless skinless chicken breast","3 chipotle peppers","4 tbsp adobo sauce","1/3 cup cilantro (chopped)","Juice of 1 lime","1/2 red bell pepper (diced)","2 scallions (thinly sliced)","1 head lettuce","Salt and freshly ground pepper"],"instructions":["Heat the olive oil in a large pan over medium heat.","Sprinkle the chicken with salt and pepper on both sides and place in the pan. Cook for 5-6 minutes per side until the chicken is cooked through.","Set aside and rest for 5 minutes, then shred.","In a food processor or blender, combine the chipotle peppers, adobo, cilantro, and lime juice. Blend until smooth.","Add the bell pepper, adobo mixture, and chicken to the saute pan on low heat. Stir well to combine and cook for 3-4 minutes.","Add the scallions to the pan.","Spoon the mixture into lettuce wraps and serve."],"pdf":"maintenance-recipes/sotas-spicy-chicken-wraps.pdf","img":"images/members/maintenance-recipes/sotas-spicy-chicken-wraps.jpg","originalFile":"SOTA Maintenance Recipe Spicy Chicken Wraps.pdf"},{"id":"sotas-spicy-lime-chicken","title":"SOTA's Spicy Lime Chicken","category":"chicken","tags":["spicy"],"servings":"Serves 2","ingredients":["1/4 teaspoon salt","1/8 teaspoon ground pepper","1/8 teaspoon cayenne pepper","1/8 teaspoon paprika","1 teaspoon garlic powder","1/8 teaspoon onion powder","1/8 teaspoon dried thyme","1/8 teaspoon dried parsley","2 boneless chicken breasts","1 tablespoon butter","1/2 teaspoon extra virgin olive oil","1 tablespoon lime juice"],"instructions":["In a small bowl, mix together salt, black pepper, cayenne, paprika, 1/4 teaspoon garlic powder, onion powder, thyme and parsley.","Sprinkle spice mixture generously on both sides of chicken breasts.","Heat butter and olive oil in a large heavy skillet over medium heat.","Saute chicken until golden brown, about 6 minutes on each side.","Sprinkle with 2 teaspoons garlic powder and lime juice. Cook 5 minutes more, stirring frequently to coat evenly with sauce."],"pdf":"maintenance-recipes/sotas-spicy-lime-chicken.pdf","img":"images/members/maintenance-recipes/sotas-spicy-lime-chicken.jpg","originalFile":"SOTA Maintenance Recipe Spicy Lime Chicken.pdf"},{"id":"state-of-the-art-snacks","title":"State of the Art Snacks","category":"snack","tags":["low-carb"],"servings":"","ingredients":["Hard boiled or deviled eggs","Pork rinds","Full-fat string cheese","Lettuce wraps with tuna, chicken, or turkey","Oven roasted cauliflower with paprika, salt, pepper, garlic, & avocado oil","Jalapenos stuffed with cream cheese","Cucumber sandwiches with cheese and tuna","Roasted edamame","Beef jerky with no added sugars","Eggs baked into half an avocado slice or bell pepper","Stuffed mushrooms","Zoodles - Zucchini spiraled into noodles then boiled and dressed with homemade pesto","Kale chips","Plain Greek yogurt sweetened with vanilla stevia drops","Broccoli with extra virgin olive oil and garlic (can also add parmesan cheese)","Caprese salad","Raw nuts such as almonds, walnuts, and macadamia nuts with extra virgin olive oil and sea salt","Celery, cucumber, bell peppers, and carrots with hard cheeses, natural almond butter or natural peanut butter, cottage cheese, or full-fat dressings","Turkey roll-ups","Hummus and red-bell pepper wedges","Peaches, plums, apricots, and all berries such as cherries, raspberries, strawberries, and blueberries","Avocado and tomato slices seasoned with sea salt","Tuna or chicken egg salad made with homemade, or REAL mayonnaise"],"instructions":["Low carb treats that taste great and help you maintain a healthy lifestyle! Choose from the list of snack ideas above."],"pdf":"maintenance-recipes/state-of-the-art-snacks.pdf","img":"images/members/maintenance-recipes/state-of-the-art-snacks.jpg","originalFile":"SOTA Maintenance Recipe State of the Art Snacks.pdf"},{"id":"sunny-breakfast-hash","title":"Sunny Breakfast Hash","category":"breakfast","tags":[],"servings":"Serves 2","ingredients":["1 lb (16 oz.) grated cauliflower","3 tablespoons butter","Salt and pepper","4 eggs","3 oz. poblano peppers","1 teaspoon olive oil","1/2 cup mayonnaise","1 teaspoon garlic powder or onion powder (optional)"],"instructions":["Mix mayonnaise and garlic or onion powder in a small bowl and set aside.","Grate the cauliflower, including the stem; either use a grater or chop into rough but fairly small pieces in a food processor.","Fry grated cauliflower for about five minutes in a generous amount of butter or oil. Season with salt and pepper to taste.","Brush some oil on the poblanos. Grill until the skin starts to bubble a little bit."],"pdf":"maintenance-recipes/sunny-breakfast-hash.pdf","img":"images/members/maintenance-recipes/sunny-breakfast-hash.jpg","originalFile":"SOTA Maintenance Recipe Sunny Breakfast Hash.pdf"},{"id":"sweet-and-spicy-chicken-wings","title":"Sweet & Spicy Chicken Wings","category":"chicken","tags":["spicy"],"servings":"Serves 2","ingredients":["1 lb (16 oz.) chicken wings","1 teaspoon sea salt","6 tablespoons coconut aminos","1 teaspoon ground ginger","1 teaspoon onion powder","1 teaspoon garlic powder","1 teaspoon chili flakes"],"instructions":["Preheat oven to 450 degrees F.","Sprinkle the wings with Pink Himalayan Sea Salt (or salt of your choice).","Bake the wings for 45 minutes.","When the wings have 12 minutes left to bake, start the sauce. Heat a medium to large skillet over medium heat, and add the coconut aminos.","Add the ginger powder, garlic powder, onion powder, and red pepper flakes.","Once the sauce comes to a simmer, begin stirring. Continue to stir periodically, once the sauce has thickened slightly as you stir it, it should take a few seconds for the sauce to fill back behind your spoon or spatula you can reduce the heat to low while the wings finish cooking.","Place the wings in a large bowl, and pour the sauce over them. Stir to evenly coat with the sauce, and serve."],"pdf":"maintenance-recipes/sweet-and-spicy-chicken-wings.pdf","img":"images/members/maintenance-recipes/sweet-and-spicy-chicken-wings.jpg","originalFile":"SOTA Maintenance Recipe Sweet & Spicy Chicken.pdf"},{"id":"thai-meat-balls","title":"Thai Meat Balls","category":"pork","tags":["spicy"],"servings":"Serves 2","ingredients":["1 lb. (16 oz.) ground pork","1/2 yellow onion, minced","1 tablespoon fresh ginger, grated","1/2 tablespoon fish sauce","1 teaspoon ground black pepper","1 tablespoon coconut oil","1 cup green cabbage","1 tbsp butter or coconut oil","1/4 cup scallions","1/2 tablespoon rice vinegar","1 tablespoon water","1/4 teaspoon salt","1/2 red chili pepper","1 oz. radishes","6 tablespoons mayo","Salt and pepper","1 tablespoon fresh thai basil, finely chopped"],"instructions":["Slice the chili pepper and scallions for the pickled onion salad.","Mix rice vinegar, water and salt in a small bowl. Add chili and scallions and set aside for 5-10 minutes.","Chop radishes finely and mix with the Thai basil and mayonnaise. Add salt and pepper to taste. Reserve.","Preheat the oven to 200 degrees F.","Mix all meatball ingredients. Shape into balls. Fry in oil until thoroughly cooked and golden brown. Keep warm in the oven.","Shred the cabbage, fry in butter or oil in a large skillet placed on medium high heat. Stir occasionally until the cabbage is browned. Season with salt and pepper.","Plate the cabbage with the meatballs on top and serve the sauce and pickled onions on the side."],"pdf":"maintenance-recipes/thai-meat-balls.pdf","img":"images/members/maintenance-recipes/thai-meat-balls.jpg","originalFile":"SOTA Maintenance Recipe Thai Meat Balls.pdf"},{"id":"zucchini-egg-salad","title":"Zucchini Egg Salad","category":"veggies","tags":["salad"],"servings":"Serves 2","ingredients":["1 lb (16 oz.) zucchini","1 tablespoon butter or avocado oil","1/2 cup mayonnaise","2 hardboiled eggs, chopped","1 green bell pepper, the seeds removed","2 celery stalks, thinly sliced","2 dill pickles (chopped)","2 tsp finely chopped scallions","1 tablespoon pickled jalapenos","1 tablespoon finely chopped fresh chives","1/4 tablespoon Dijon mustard","Salt and pepper"],"instructions":["Peel and cut the zucchini into pieces that are about half an inch (1-1.5 cm) thick. Use a spoon to remove the seeds.","Place in a colander and add salt. Leave for 5-10 minutes and then cautiously press out the water.","Fry the cubes in butter for a couple of minutes over medium heat. They should not brown, just slightly soften. Set aside to cool.","Mix the other ingredients in a big bowl and add the zucchini once it's cool."],"pdf":"maintenance-recipes/zucchini-egg-salad.pdf","img":"images/members/maintenance-recipes/zucchini-egg-salad.jpg","originalFile":"SOTA Maintenance Recipe Zucchini Egg Salad.pdf"},{"id":"zucchini-steak-boats","title":"Zucchini Steak Boats","category":"beef","tags":[],"servings":"Serves 2","ingredients":["2 zucchini, sliced in half lengthwise","1/2 lb thinly sliced roast beef, chopped into small pieces","1 yellow onion, sliced","1 garlic clove, minced","3 oz. mushrooms, sliced","1 bell pepper, chopped","1 tbsp extra virgin olive oil","Sea salt and freshly ground black pepper"],"instructions":["Preheat your oven to 400 F.","Scoop out the center of each zucchini half to create \"boats\" with a hollow center, but make sure to leave a thick rim.","Brush the zucchinis with olive oil and season with salt and pepper to taste.","Bake the zucchini in the preheated oven for 15 to 20 minutes.","Melt some cooking fat in a skillet placed over a medium heat. Saute the onion and garlic for 2 to 3 minutes.","Add the bell pepper and mushrooms, and cook until soft, about 5 minutes.","Add in roast beef, season everything to taste, and cook for 2 to 3 minutes, stirring.","Fill each zucchini with the beef mixture and serve."],"pdf":"maintenance-recipes/zucchini-steak-boats.pdf","img":"images/members/maintenance-recipes/zucchini-steak-boats.jpg","originalFile":"SOTA Maintenance Recipe Zucchini Steak Boats.pdf"},{"id":"grab-n-go-sota-egg-bites","title":"Grab-N-Go SOTA Egg Bites","category":"breakfast","tags":["low-carb"],"servings":"Makes 9 muffin-sized egg bites","ingredients":["3 Tbsp Bacon fat","1/4 cup onion, finely diced","1.5 cups fresh spinach/kale","6 eggs","5 slices bacon chopped and cooked","3/4 cup shredded cheddar cheese","1/3 cup half & half or heavy cream","1/2 tsp salt & pepper (or to taste)"],"instructions":["Preheat oven to 350 degrees.","In a pan cook your bacon on medium heat till done.","Leave about 3 tablespoons of bacon fat in the pan. Add onion and cook for about 2 minutes. Add spinach/kale and cook until wilted, about 2-3 more minutes. Remove from the heat.","In a bowl, whisk with a fork the eggs, cream, and the cheese. Season with the salt and pepper. Add the spinach mixture and the bacon and stir until well-combined.","Use a muffin tin with non-stick spray or muffin liners.","Evenly distribute the bacon to the bottom of 9 muffin tins.","Evenly distribute the egg mixture amongst each muffin tin (fill about 3/4 of the way). Bake for about 20 minutes or until the muffins have turned a light golden brown around the edges.","Store muffins in the fridge in an airtight container. To reheat, stick in the microwave for about 20-30 seconds."],"pdf":"maintenance-recipes/grab-n-go-sota-egg-bites.pdf","img":"images/members/maintenance-recipes/grab-n-go-sota-egg-bites.jpg","originalFile":"SOTA Maintenance Recipes Grab-N-Go SOTA Egg Bites.pdf"},{"id":"moms-green-sauce","title":"Mom's Green Sauce","category":"sauces","tags":["spicy"],"servings":"","ingredients":["1 cup mayo","1 jalapeno","1 lime squeezed","2/3 cup cilantro (about 2/3's the bunch)","2 pinches of salt"],"instructions":["If you don't want much spice, take all the seeds out of the jalapeno. Leave some seeds or all for spicy green sauce.","Place all ingredients in a blender and blend."],"pdf":"maintenance-recipes/moms-green-sauce.pdf","img":"images/members/maintenance-recipes/moms-green-sauce.jpg","originalFile":"SOTA Maintenance Recipes Green Sauce.pdf"},{"id":"heavenly-sota-cheesecake-fat-treat","title":"Heavenly SOTA Cheesecake Fat Treat","category":"snack","tags":["low-carb"],"servings":"Serving size: 3 treats","ingredients":["6 ounces cream cheese","1/2 cup strawberries or raspberries","4 Tbsp salted Kerry Gold butter","4 tsp Swerve Sweetener (Or 4 tsp Monk Fruit sweetener or 1/3 tsp liquid stevia)","1.5 tsp vanilla extract"],"instructions":["Let the cream cheese and butter sit at room temperature for about an hour to soften before mixing.","Blend the strawberries using a blender or mash by hand.","In a bowl, combine strawberries, vanilla and sweetener (you can always add more sweetener at the end, sweeten to your taste.)","In a separate bowl, microwave the cream cheese and butter for 10 seconds until very soft and pliable.","Add strawberry mix to the bowl with the butter and cream cheese. Use an electric hand mixer until well-mixed, ideally without any large cream cheese clumps remaining.","Use two spoons to help divide the batter into 30 balls the size of a cherry tomato.","Freeze until solid, about 2 hours before serving. Store leftovers in the freezer."],"pdf":"maintenance-recipes/heavenly-sota-cheesecake-fat-treat.pdf","img":"images/members/maintenance-recipes/heavenly-sota-cheesecake-fat-treat.jpg","originalFile":"SOTA Maintenance Recipes Heavenly SOTA Cheesecake Fat Treat.pdf"},{"id":"low-carb-turkey-burgers-2","title":"Low Carb Turkey Burgers","category":"chicken","tags":["low-carb","grill"],"servings":"Varies per SOTA client","ingredients":["1 lb. (16 oz.) ground turkey","1 tsp onion powder","1 tsp paprika","1/2 tsp salt","1/2 tsp freshly ground pepper","1/2 tsp coriander","Pinch of cayenne","2 green onions (chopped)","1 tomato (sliced)","2 cups fresh spinach or arugula"],"instructions":["Add the ground turkey, onion powder, paprika, salt, pepper, coriander, cayenne, and green onions to a large bowl and stir to combine.","Heat the grill to medium heat and cook burgers for 5-6 minutes on each side until cooked through.","Serve the burgers on spinach with a slice of tomato and slice of avocado!"],"pdf":"maintenance-recipes/low-carb-turkey-burgers-2.pdf","img":"images/members/maintenance-recipes/low-carb-turkey-burgers-2.jpg","originalFile":"SOTA Maintenance Recipes Low Carb Turkey Burgers.pdf"},{"id":"marinated-grilled-shrimp-2","title":"Marinated Grilled Shrimp","category":"seafood","tags":["grill"],"servings":"Serves 2","ingredients":["1/3 cup avocado oil","1 tbsp. parsley","1 lemon (juice)","2 tsp hot sauce","1 clove garlic (minced)","1 tsp oregano","1/4 tsp salt","1/4 tsp pepper","5-8 shrimp (per person)"],"instructions":["In a mixing bowl, mix together avocado oil, parsley, lemon juice, hot sauce, garlic, oregano, salt and pepper.","Reserve small amount for basting later.","Pour remaining marinade into a large resealable plastic bag with shrimp. Seal, and marinade in the refrigerator for 2 hours.","Preheat grill for medium low heat.","Thread shrimp onto skewers. Cook shrimp for 5 minutes per side frequently basting with reserved marinade!"],"pdf":"maintenance-recipes/marinated-grilled-shrimp-2.pdf","img":"images/members/maintenance-recipes/marinated-grilled-shrimp-2.jpg","originalFile":"SOTA Maintenance Recipes Marinated Grilled Shrimp.pdf"},{"id":"no-bake-sota-style-cheesecake-fat-treat","title":"No Bake SOTA Style Cheesecake Fat Treat","category":"snack","tags":["low-carb"],"servings":"Makes 4 servings","ingredients":["2 tsp stevia drops (or to taste)","1/2 cup frozen strawberries","1 cup heavy whipping cream (full fat)","1/2 tsp stevia drops (or to taste)","1 lemon zested","2 Tbsp lemon juice","8 oz cream cheese at room temp"],"instructions":["In a nonstick sauce pan, cook your strawberries and stevia until you get a thick consistency (jam like). This should take 5-8 minutes. Set it aside and let it completely cool down.","Using an electric mixer, mix cream cheese, lemon juice, lemon zest and stevia (use any flavor stevia you choose) until you get a creamy consistency.","In a separate bowl, use the electric mixer to whip the whipping cream until it gets thick and firm. Don't over whip it, the cream should be just thick enough that it stays on the mixer once you lift it. If you over whip it, add a little splash of heavy cream and mix it gently.","Add half of your whipped cream to your cream cheese filling and fold it in. Now add the other half, this time mix it in gently to make sure that your creamy filling remains light.","Take 4 small bowls (ramekin, or espresso cups would work also), place your cheesecake filling in the 4 bowls. Using the back of the spoon, spread it evenly and make sure the top is flat. Cover your bowls and let them chill in the fridge for at least 30 minutes, ideally 1 hour.","Take out of the fridge and scoop 1 tablespoon of your berry jam and place it on top of your cheesecake."],"pdf":"maintenance-recipes/no-bake-sota-style-cheesecake-fat-treat.pdf","img":"images/members/maintenance-recipes/no-bake-sota-style-cheesecake-fat-treat.jpg","originalFile":"SOTA Maintenance Recipes No Bake SOTA Style Cheesecake Fat Treat.pdf"},{"id":"delicious-salsa-verde-2","title":"Delicious Salsa Verde","category":"sauces","tags":[],"servings":"Serves 2","ingredients":["1/4 cup finely chopped parsley","2 tbsp. chopped cilantro","1 crushed garlic clove","1/4 lemon (the juice)","1 tbsp. small capers","1/2 cup extra virgin olive oil","1/2 teaspoon sea salt","1/4 teaspoon ground black pepper"],"instructions":["Add all the ingredients to a deep bowl and mix with a blender until the sauce has a desired consistency.","Store the sauce in the refrigerator for up to 4-5 days or in the freezer!"],"pdf":"maintenance-recipes/delicious-salsa-verde-2.pdf","img":"images/members/maintenance-recipes/delicious-salsa-verde-2.jpg","originalFile":"SOTA Maintenance Recipes Salsa Verde.pdf"},{"id":"spicy-chicken-wraps","title":"Spicy Chicken Wraps","category":"chicken","tags":["spicy"],"servings":"Varies per SOTA client","ingredients":["2 tbsp. avocado oil","1 lb. (16 oz) boneless skinless chicken breast","3 chipotle peppers","1/3 cup cilantro (chopped)","1 lime (juice)","1 red bell pepper (diced)","2 scallions (sliced)","1 head of lettuce","Salt & pepper to taste"],"instructions":["Heat the avocado oil in a large pan over medium heat.","Sprinkle the chicken with salt and pepper on both sides and place in pan. Cook for 5-6 minutes per side until chicken is cooked through.","Set aside and rest for 5 minutes, then shred.","In a food processor or blender, combine the peppers, cilantro, and lime juice. Blend until smooth.","Add the mixture to chicken to saute in pan over low heat. Stir well and let cook for 3-4 min.","Add scallions to the pan.","Lastly, spoon mixture into lettuce wraps and serve!"],"pdf":"maintenance-recipes/spicy-chicken-wraps.pdf","img":"images/members/maintenance-recipes/spicy-chicken-wraps.jpg","originalFile":"SOTA Maintenance Recipes Spicy Chicken Wraps.pdf"},{"id":"spicy-ranch-mix","title":"Spicy Ranch Mix","category":"sauces","tags":["spicy"],"servings":"Serves 2","ingredients":["2 tsp salt","4 tbsp. parsley","3 tsp dill weed","2 tsp dried chives","4 tsp garlic powder","4 tsp onion powder","4 tsp dried onion flakes","2 tsp black pepper"],"instructions":["Mix all ingredients together.","Mix with Avocado oil to marinade meat, or sprinkle over veggies you are grilling or sauteing/roasting!"],"pdf":"maintenance-recipes/spicy-ranch-mix.pdf","img":"images/members/maintenance-recipes/spicy-ranch-mix.jpg","originalFile":"SOTA Maintenance Recipes Spicy Ranch Mix.pdf"},{"id":"sota-chocolate-or-berry-muffins","title":"SOTA Chocolate or Berry Muffins","category":"snack","tags":["low-carb"],"servings":"Makes 12 muffins","ingredients":["1 1/2 cup blanched Almond Flour","1/2 cup Unsweetened Cocoa Powder","3 Tablespoon Monk Fruit sweetener or Swerve sweetener","1 1/2 teaspoons Baking Powder","1 Teaspoon of Vanilla Extract","3 Eggs","2/3 Cup Heavy Cream","6 Tablespoons Butter, melted","1/2 Cup of Sugar-Free Chocolate Chips","For Blueberry variation: 1 cup blueberries (instead of cocoa powder and chocolate chips)","For Blueberry variation: Additional 1/2 cup almond flour","For Blueberry variation: 1/2 tsp cinnamon"],"instructions":["Preheat oven to 350F.","In a bowl, combine almond flour, cocoa powder, sweetener and baking powder. (Add cinnamon if making blueberry muffins.)","Add the vanilla extract, eggs, and heavy cream. Mix well.","Add the melted butter and combine.","Add the sugar-free chocolate chips or blueberries and stir well.","Spoon the mixture into 12 holes of a standard muffin tray that has been lined with cupcake papers.","Bake for 20-25 minutes, the muffins will look puffed up and slightly spring back when touched.","Allow to cool in the muffin tin or eat them straight away - beware of the molten chocolate chips. The muffins will shrink back a little as they cool."],"pdf":"maintenance-recipes/sota-chocolate-or-berry-muffins.pdf","img":"images/members/maintenance-recipes/sota-chocolate-or-berry-muffins.jpg","originalFile":"SOTA Maintenance SOTA Blueberry Chocolate Muffins.pdf"}]